import { useMemo, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import axios from "axios"; 
import quizzes from "../data/quizzes";
import "../App.css";

function QuizAttempt() {
  const { id } = useParams();
  const navigate = useNavigate();
  const quiz = useMemo(() => quizzes.find((q) => q.id === Number(id)), [id]);

  const [answers, setAnswers] = useState({});
  const [errorMessage, setErrorMessage] = useState("");
  const [unansweredIds, setUnansweredIds] = useState([]);
  const [isSubmitting, setIsSubmitting] = useState(false); 

  if (!quiz) return <div className="page-container">Quiz not found.</div>;

  const handleOptionChange = (questionId, selectedOption) => {
    setAnswers((prev) => ({ ...prev, [questionId]: selectedOption }));
    setErrorMessage("");
    setUnansweredIds((prev) => prev.filter((id) => id !== questionId));
  };

  const handleSubmit = async () => {
    const unansweredQuestions = quiz.questions.filter((question) => !answers[question.id]);
    if (unansweredQuestions.length > 0) {
      setUnansweredIds(unansweredQuestions.map((q) => q.id));
      setErrorMessage("Please answer all questions before submitting the quiz.");
      window.scrollTo({ top: 0, behavior: "smooth" });
      return;
    }

    setIsSubmitting(true);
    let score = 0;
    quiz.questions.forEach((question) => {
      if (answers[question.id] === question.correctAnswer) score += 1;
    });

    const userString = localStorage.getItem("user");
    const user = userString ? JSON.parse(userString) : null;
    const userEmail = user?.email || "anonymous@student.com"; 

    const attemptData = {
      email: userEmail,
      quizId: quiz.id,
      quizTitle: quiz.title,
      score: score,
      totalQuestions: quiz.questions.length
    };

    try {
      await axios.post("http://localhost:8086/api/quiz-attempts", attemptData);
      navigate("/quiz-result", { state: { title: quiz.title, score, total: quiz.questions.length } });
    } catch (error) {
      console.error("Failed to save quiz attempt:", error);
      setErrorMessage("Failed to save your score. Please try submitting again.");
      setIsSubmitting(false);
    }
  };

  return (
    <div className="page-container">
      <h1 className="page-title">{quiz.title}</h1>
      <p className="page-subtitle"><strong>Subject:</strong> {quiz.subject} | <strong>Video:</strong> {quiz.videoTitle}</p>
      {errorMessage && <div className="error-box"><strong>Notice:</strong> {errorMessage}</div>}

      {quiz.questions.map((question, index) => (
        <div key={question.id} className={`question-card ${unansweredIds.includes(question.id) ? "question-error" : ""}`}>
          <h3>{index + 1}. {question.questionText}</h3>
          {question.options.map((option) => (
            <div key={option} style={{ marginTop: "10px" }}>
              <label>
                <input type="radio" name={`question-${question.id}`} value={option} checked={answers[question.id] === option} onChange={() => handleOptionChange(question.id, option)} disabled={isSubmitting} />
                {" "}{option}
              </label>
            </div>
          ))}
          {unansweredIds.includes(question.id) && <p className="question-error-text">Please select an answer</p>}
        </div>
      ))}

      <button className="quiz-button" onClick={handleSubmit} disabled={isSubmitting}>
        {isSubmitting ? "Saving Score..." : "Submit Quiz"}
      </button>
    </div>
  );
}
export default QuizAttempt;
